const filteredData = useMemo(() => {
  if (!filterText) return sortedData;
  const lowerFilter = filterText.toLowerCase();
  return sortedData.filter(row =>
    columns.some(col =>
      String(row[col.key]).toLowerCase().includes(lowerFilter)
    )
  );
